    otlp_span_event_destroy(&span->events.ptr[i]);
  free(span->events.ptr);
  for (i = 0; i < span->links.len; ++i)
    otlp_span_link_destroy(&span->links.ptr[i]);
  free(span->links.ptr);
  if (span->has_status)
    otlp_trace_status_destroy(&span->status);
  otlp_span_init(span);
